#!/usr/bin/env bash
set -euo pipefail

SAHAR_INSTALLER_VERSION="0.1.63"
DEFAULT_WORKDIR="/opt/sahar"
MODE="master"
WORKDIR="$DEFAULT_WORKDIR"
EXTRACT_ONLY=""

read -r -d '' PAYLOAD_B64 <<'__SAHAR_PAYLOAD__' || true

__SAHAR_PAYLOAD__

usage() {
  cat <<'EOF'
Sahar single-file installer v0.1.63

Usage:
  bash <(curl -Ls https://raw.githubusercontent.com/PooyanGhorbani/Sahar/main/sahar-installer.sh) master
  bash <(curl -Ls https://raw.githubusercontent.com/PooyanGhorbani/Sahar/main/sahar-installer.sh) agent

Options:
  --workdir DIR       Extract code to DIR before running installer
  --extract-only DIR  Only extract files to DIR and exit
  -h, --help          Show this help

Notes:
  - Cloudflare Tunnel / Argo Tunnel support is included.
  - Running with bash process substitution requires bash to already exist on the host.
  - On Alpine without bash, install bash first.
EOF
}

args=()
while [[ $# -gt 0 ]]; do
  case "$1" in
    master|agent)
      MODE="$1"
      shift
      ;;
    --workdir)
      [[ $# -ge 2 ]] || { echo "Missing value for --workdir" >&2; exit 1; }
      WORKDIR="$2"
      shift 2
      ;;
    --extract-only)
      [[ $# -ge 2 ]] || { echo "Missing value for --extract-only" >&2; exit 1; }
      EXTRACT_ONLY="$2"
      shift 2
      ;;
    -h|--help)
      usage
      exit 0
      ;;
    *)
      args+=("$1")
      shift
      ;;
  esac
done

if [[ "$MODE" != "master" && "$MODE" != "agent" ]]; then
  echo "Invalid mode: $MODE" >&2
  usage >&2
  exit 1
fi

if [[ $EUID -ne 0 ]]; then
  echo "This installer must be run as root." >&2
  exit 1
fi

TMP_DIR=$(mktemp -d /tmp/sahar-single-installer.XXXXXX)
cleanup() { rm -rf "$TMP_DIR"; }
trap cleanup EXIT

mkdir -p "$TMP_DIR/payload"
printf '%s' "$PAYLOAD_B64" | base64 -d | tar -xzmf - -C "$TMP_DIR/payload"

TARGET_DIR="$WORKDIR"
if [[ -n "$EXTRACT_ONLY" ]]; then
  TARGET_DIR="$EXTRACT_ONLY"
fi
rm -rf "$TARGET_DIR"
mkdir -p "$TARGET_DIR"
cp -a "$TMP_DIR/payload"/. "$TARGET_DIR"/

if [[ -n "$EXTRACT_ONLY" ]]; then
  echo "Extracted to: $TARGET_DIR"
  exit 0
fi

cd "$TARGET_DIR"
if [[ "$MODE" == "master" ]]; then
  exec bash ./install_master.sh "${args[@]}"
else
  exec bash ./install_agent.sh "${args[@]}"
fi
